      "content": "import { BaseRoute } from './base';
import { Station } from '../core/types';

export class ProductRoute extends BaseRoute {
  constructor(
    id: string,
    name: string,
    stations: string[],
    productId: string
  ) {
    super(id, name, stations, productId);
  }

