      "path": "factory-system/index.ts",
      "content": "import { AssemblyStation } from './stations/assembly';
import { ProcessingStation } from './stations/processing';
import { QualityStation } from './stations/quality';
import { StorageStation } from './stations/storage';
import { ProductRoute } from './routing/route';
import { ExampleProduct } from './products/product';

// Create stations
const assemblyStation = new AssemblyStation('station-001', 'Assembly Line', 10);
const processingStation = new ProcessingStation('station-002', 'Processing Unit', 5);
const qualityStation = new QualityStation('station-003', 'Quality Check', 3);
const storageStation = new StorageStation('station-004', 'Warehouse', 20);

// Create product
const product = new ExampleProduct();

// Create route
const route = new ProductRoute('route-001', 'Production Route', 
  ['station-001', 'station-002', 'station-003', 'station-004'], 
  'prod-001'
);

// Execute route
route.execute();

// Process product through stations
assemblyStation.process();
processingStation.process();
qualityStation.process();
storageStation.process();

console.log('Factory operations completed');"
    }
